tool_calls.call:
cat > /tmp/test_bug.c << 'EOF'
#include <stdio.h>
#include <yara.h>

int main() {
  YR_COMPILER* compiler = NULL;
  const char* rules_str = "rule test { condition: true }";

  yr_initialize();

  if (yr_compiler_create(&compiler) != ERROR_SUCCESS) {
    printf("Failed to create compiler\n");
    return 1;
  }

  // Define a variable named "test"
  yr_compiler_define_boolean_variable(compiler, "test", 1);

  // Try to compile a rule also named "test"
  yr_compiler_add_string(compiler, rules_str, NULL);

  printf("last_error = %d (expected 14 for ERROR_DUPLICATED_IDENTIFIER)\n", 
         compiler->last_error);

  yr_compiler_destroy(compiler);
  yr_finalize();
  return 0;
}
EOF
gcc -o /tmp/test_bug /tmp/test_bug.c -I/work/libyara/include -L/work/libyara/.libs -lyara 2>&1
